const tender = $('load-requirements').first().json;
const profile = $('load-company-profile').first().json || {};

// Build company profile object for LLM
const companyProfile = {
  name: profile.company_name || profile.name || 'Unbekanntes Unternehmen',
  capabilities_summary: profile.capabilities_summary || '',
  certifications: profile.certifications || [],
  trades: profile.trades || [],
  regions: profile.regions || [],
  service_types: profile.service_types || [],
  project_references: profile.project_references || [],
  // HQ address for distance calculation (IMP-03b)
  hq_street:      profile.hq_street      || null,
  hq_postal_code: profile.hq_postal_code || null,
  hq_city:        profile.hq_city        || null,
};

const requirements = tender.requirements || [];

// Bauort context for distance/travel risk assessment
const bauort = tender.region || null;

// Wertschöpfungsanalyse — from stage 2 classification
const vb = tender.value_breakdown || null;
const valueBreakdownNote = vb ? (function() {
  const s = vb.summary || {};
  const total = s.total || 1;
  const fremdPct = Math.round((s.fremd || 0) / total * 100);
  const lieferPct = Math.round((s.liefer || 0) / total * 100);
  const gemischtPct = Math.round((s.gemischt || 0) / total * 100);
  const eigenPct = 100 - fremdPct - lieferPct - gemischtPct;
  const parts = [];
  if (eigenPct > 0)    parts.push(eigenPct + '% Eigenleistung (' + s.eigen + ' Pos.)');
  if (fremdPct > 0)    parts.push(fremdPct + '% Fremdleistung (' + s.fremd + ' Pos.)');
  if (lieferPct > 0)   parts.push(lieferPct + '% Lieferleistung (' + s.liefer + ' Pos.)');
  if (gemischtPct > 0) parts.push(gemischtPct + '% Mischleistung (' + s.gemischt + ' Pos.)');
  return parts.join(', ');
})() : null;
const companyRegions = profile.regions || [];
// Simple heuristic: flag if Bauort is not within any of the company's listed regions
// e.g. company covers 'Bayern', Bauort is 'Nordrhein-Westfalen' → outside service area
const bauortOutsideRegions = bauort && companyRegions.length > 0
  ? !companyRegions.some(r => bauort.toLowerCase().includes(r.toLowerCase()) || r.toLowerCase().includes(bauort.toLowerCase()))
  : false;

return [{ json: {
  tender_id: tender.id,
  company_profile: companyProfile,
  requirements,
  requirements_json: JSON.stringify(requirements),
  bauort,
  bauort_outside_regions: bauortOutsideRegions,
  company_regions_str: companyRegions.join(', ') || 'nicht angegeben',
  value_breakdown_note: valueBreakdownNote,
} }];

// ─── Distance calculation node ───────────────────────────────────────────────
// Provider-agnostic distance calculation between company HQ and Bauort.
// To swap provider: replace the `geocode()` function body only.
// Current provider: Nominatim (OpenStreetMap) — free, no API key required.
//
// Returns distance_km (straight-line Haversine) + geocode metadata.
// Fails gracefully: if geocoding fails, distance_km = null and evaluation continues.

const ctx = $json;

// ─── Provider: Nominatim ─────────────────────────────────────────────────────
// To use OpenRouteService: replace URL + parse response accordingly.
// To use Google Maps: replace with Distance Matrix API call.
async function geocode(query) {
  const url = 'https://nominatim.openstreetmap.org/search?format=json&limit=1&q=' +
    encodeURIComponent(query);
  const resp = await fetch(url, {
    headers: { 'User-Agent': 'Tenderly/1.0 (tender-analysis)' },
    signal: AbortSignal.timeout(8000),
  });
  if (!resp.ok) throw new Error(`Nominatim HTTP ${resp.status}`);
  const data = await resp.json();
  if (!data || !data.length) return null;
  return { lat: parseFloat(data[0].lat), lon: parseFloat(data[0].lon), display: data[0].display_name };
}

// ─── Haversine formula ────────────────────────────────────────────────────────
// Straight-line distance in km. Accurate enough for go/no-go decisions.
// Typical road distance is ~1.2–1.4x straight-line for Central Europe.
function haversine(lat1, lon1, lat2, lon2) {
  const R = 6371;
  const dLat = (lat2 - lat1) * Math.PI / 180;
  const dLon = (lon2 - lon1) * Math.PI / 180;
  const a = Math.sin(dLat/2)**2 +
    Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180) *
    Math.sin(dLon/2)**2;
  return R * 2 * Math.asin(Math.sqrt(a));
}

// ─── Build geocode queries ────────────────────────────────────────────────────
const profile = ctx.company_profile || {};
const hqCity   = profile.hq_city        || null;
const hqPostal = profile.hq_postal_code || null;
const hqStreet = profile.hq_street      || null;
const bauort   = ctx.bauort             || null;

// Build address strings — as specific as available, Germany assumed
const hqQuery = hqPostal && hqCity
  ? `${hqPostal} ${hqCity}, Deutschland`
  : hqCity
  ? `${hqCity}, Deutschland`
  : hqStreet && hqCity
  ? `${hqStreet}, ${hqCity}, Deutschland`
  : null;

const bauortQuery = bauort ? `${bauort}, Deutschland` : null;

// ─── Geocode both and compute distance ───────────────────────────────────────
let distanceKm   = null;
let distanceNote = null;
let hqGeo        = null;
let bauortGeo    = null;

if (hqQuery && bauortQuery) {
  try {
    [hqGeo, bauortGeo] = await Promise.all([geocode(hqQuery), geocode(bauortQuery)]);
    if (hqGeo && bauortGeo) {
      distanceKm = Math.round(haversine(hqGeo.lat, hqGeo.lon, bauortGeo.lat, bauortGeo.lon));
      // Rough road-distance estimate (Haversine × 1.3 for Central Europe)
      const roadEstimate = Math.round(distanceKm * 1.3);
      distanceNote = `ca. ${distanceKm} km Luftlinie (ca. ${roadEstimate} km Fahrtstrecke geschätzt) von ${hqCity || 'Firmensitz'} nach ${bauort}`;
    } else {
      distanceNote = 'Geocodierung nicht erfolgreich — Entfernung unbekannt';
    }
  } catch (e) {
    distanceNote = 'Geocodierung fehlgeschlagen: ' + String(e).slice(0, 80);
  }
} else if (!hqQuery) {
  distanceNote = 'Firmenanschrift nicht hinterlegt — Entfernung nicht berechnet';
} else {
  distanceNote = 'Bauort unbekannt — Entfernung nicht berechnet';
}

return [{ json: {
  ...ctx,
  distance_km:    distanceKm,
  distance_note:  distanceNote,
  hq_geo:         hqGeo,
  bauort_geo:     bauortGeo,
}}];

const tenderId = $('load-requirements').first().json.id;
let evaluation;
try {
  const content = $json.choices[0].message.content;
  evaluation = typeof content === 'string' ? JSON.parse(content.replace(/```json|```/g, '').trim()) : content;
} catch(e) {
  evaluation = { strategic_fit_score: 0, bid_recommendation: 'needs_review', rationale: '', strengths: [], eligibility_summary: { compliant_count: 0, partial_count: 0, not_met_count: 0, blocking_issues: 0 }, eligibility_requirements: [], risks: [], clarifications: [] };
}
return [{ json: {
  id: tenderId,
  strategic_fit_score: evaluation.strategic_fit_score,
  bid_recommendation: evaluation.bid_recommendation,
  rationale: evaluation.rationale || '',
  strengths: evaluation.strengths || [],
  eligibility_summary: evaluation.eligibility_summary,
  eligibility_requirements: evaluation.eligibility_requirements,
  risks: evaluation.risks,
  clarifications: evaluation.clarifications,
  processing_status: 'complete'
} }];

const eval_data = $('parse-evaluation').first().json;
return [{ json: {
  id: eval_data.id,
  strategic_fit_score: eval_data.strategic_fit_score,
  bid_recommendation: eval_data.bid_recommendation,
  rationale: eval_data.rationale || '',
  strengths: eval_data.strengths || [],
  eligibility_summary: eval_data.eligibility_summary,
  eligibility_requirements: eval_data.eligibility_requirements || [],
  risks: eval_data.risks || [],
  clarifications: eval_data.clarifications || [],
  processing_status: 'complete'
} }];
